import numpy as np

def check_convergence(energies, gradients, params_history,
                      e_tol=1e-6, g_tol=1e-4, p_tol=1e-4, window=5):
    """
    Check if VQE optimization has converged.
    """
    if len(energies) < window:
        return {'converged': False, 'reason': 'Not enough iterations'}

    # Check energy convergence
    recent_energies = energies[-window:]
    energy_change = np.abs(recent_energies[-1] - recent_energies[0])
    energy_converged = energy_change < e_tol

    # Check gradient convergence
    if gradients:
        recent_grad = gradients[-1]
        grad_converged = recent_grad < g_tol
    else:
        grad_converged = False

    # Check parameter convergence
    if len(params_history) >= 2:
        param_change = np.linalg.norm(
            np.array(params_history[-1]) - np.array(params_history[-2])
        )
        param_converged = param_change < p_tol
    else:
        param_converged = False

    # Determine overall convergence
    if energy_converged and grad_converged:
        return {'converged': True, 'reason': 'Energy and gradient converged'}
    elif energy_converged and param_converged:
        return {'converged': True, 'reason': 'Energy and parameters converged'}
    elif energy_converged:
        return {'converged': True, 'reason': 'Energy converged'}
    else:
        return {'converged': False, 'reason': 'Not converged'}
